(async () => {
  const PHYSICAL_ATTRIBUTES = new Set([
    'agility',
    'dexterity',
    'strength',
    'constitution'
  ]);

  const getAttributeString = (node) => {
    const a = node?.attribute;
    if (typeof a === 'string') return a;
    if (a && typeof a === 'object' && typeof a.value === 'string') return a.value; // legacy
    return null;
  };

  const walk = (obj, pathParts, out) => {
    if (!obj || typeof obj !== 'object') return;

    if (Object.prototype.hasOwnProperty.call(obj, 'applyPhysicalActionMod')) {
      const attr = getAttributeString(obj);
      const shouldBeTrue = attr != null && PHYSICAL_ATTRIBUTES.has(attr);

      if (obj.applyPhysicalActionMod !== shouldBeTrue) {
        out.push({ path: pathParts.join('.'), value: shouldBeTrue });
      }
    }

    for (const [k, v] of Object.entries(obj)) {
      if (v && typeof v === 'object') walk(v, [...pathParts, k], out);
    }
  };

  const actors = canvas?.tokens?.controlled
    ?.map(t => t.actor)
    .filter(a => a);

  if (!actors?.length) {
    ui.notifications.warn('[ABF] No hay tokens seleccionados.');
    return;
  }

  let totalChanges = 0;
  let touchedActors = 0;

  for (const actor of actors) {
    const changes = [];
    walk(actor.system, ['system'], changes);

    if (!changes.length) continue;

    const updates = {};
    for (const c of changes) updates[`${c.path}.applyPhysicalActionMod`] = c.value;

    await actor.update(updates);

    totalChanges += changes.length;
    touchedActors += 1;

    console.log(`[ABF] Updated ${actor.name}:`, updates);
  }

  ui.notifications.info(
    `[ABF] applyPhysicalActionMod actualizado en ${touchedActors} actores (${totalChanges} cambios).`
  );
})();
